class LRUCache {

    private static class Node {
        int key;
        int value;
        Node prev;
        Node next;
    }

    private final Map<Integer, Node> cache;
    private final int capacity;
    private Node head, tail;

    public LRUCache(int capacity) {
        this.capacity = capacity;
        cache = new HashMap<>();
        head = new Node();
        tail = new Node();
        head.next = tail;
        tail.prev = head;
    }

    public int get(int key) {
        Node node = cache.get(key);
        if (node == null) return -1;
        moveToTail(node);
        return node.value;
    }

    public void put(int key, int value) {
        Node node = cache.get(key);
        if (node == null) {
            node = new Node();
            node.key = key;
            node.value = value;
            addNode(node);
            cache.put(key, node);
            if (cache.size() > capacity) {
                Node lru = head.next;
                removeNode(lru);
                cache.remove(lru.key);
            }
        } else {
            node.value = value;
            moveToTail(node);
        }
    }

    private void addNode(Node node) {
        node.prev = tail.prev;
        node.next = tail;
        tail.prev.next = node;
        tail.prev = node;
    }

    private void removeNode(Node node) {
        Node prev = node.prev;
        Node next = node.next;
        prev.next = next;
        next.prev = prev;
    }

    private void moveToTail(Node node) {
        removeNode(node);
        addNode(node);
    }
